                        processDsp(cec);

                        if (use_dsp_cfg_params.empty())
                            run("techmap -map " + dspMapFile + " -D USE_DSP_CFG_PARAMS=0");
                        else
                            run("techmap -map " + dspMapFile + " -D USE_DSP_CFG_PARAMS=1");

